html:
{% set fmt = lambda v: '{:,.0f}'.format(v or 0).replace(',', ' ') %}
<style>
  .bc-page { font-family: Arial, sans-serif; color:#1a1a1a; padding:0; max-width: 760px; margin: 0 auto; }
  .bc-header { display: flex; align-items: center; justify-content: space-between; padding-bottom: 8px; border-bottom: 3px solid #0E5C8A; }
  .bc-logo img { height: 70px; }
  .bc-h-center { text-align: center; flex: 1; }
  .bc-h-center h1 { color:#0E5C8A; font-size: 22px; margin: 0; letter-spacing: 2px; font-weight: 800; }
  .bc-h-center .slogan { color:#F77F00; font-size: 11px; font-style: italic; margin: 2px 0 0; }
  .bc-h-right { text-align: right; font-size: 10px; color:#0E5C8A; font-weight: 600; }
  .bc-h-right .bc-num { background: #0E5C8A; color:white; padding: 4px 10px; font-weight: 700; font-size: 11px; border-radius: 4px; }
  .bc-h-right .bc-date { color:#666; margin-top: 4px; font-size: 10px; }
  .bc-prix { font-size: 9px; color:#888; font-style: italic; margin-top: 3px; }
  .bc-objet { background: linear-gradient(135deg, #0E5C8A, #1976D2); color:white; padding: 10px 14px; margin: 14px 0; border-radius: 6px; }
  .bc-objet .lbl { font-size: 10px; text-transform: uppercase; letter-spacing: 1px; opacity: 0.85; font-weight: 600; }
  .bc-objet .val { font-size: 13px; font-weight: 700; margin-top: 2px; }
  .bc-section { display: flex; gap: 18px; margin: 12px 0; }
  .bc-block { flex: 1; border: 1px solid #d0d7de; padding: 10px 12px; border-radius: 6px; background:#fafbfc; }
  .bc-block h4 { margin: 0 0 6px; color:#0E5C8A; font-size: 11px; text-transform: uppercase; letter-spacing: 1px; border-bottom: 1px solid #d0d7de; padding-bottom: 4px; }
  .bc-block p { margin: 2px 0; font-size: 11px; }
  .bc-block strong { color:#0E5C8A; }
  table.bc-items { width: 100%; border-collapse: collapse; margin-top: 14px; font-size: 11px; }
  table.bc-items thead th { background: linear-gradient(135deg, #0E5C8A, #1976D2); color:white; padding: 8px 10px; text-transform: uppercase; font-size: 10px; letter-spacing: 1px; text-align: left; }
  table.bc-items thead th.right { text-align: right; }
  table.bc-items thead th.center { text-align: center; }
  table.bc-items tbody td { padding: 8px 10px; border-bottom: 1px solid #e2e8f0; }
  table.bc-items tbody tr:nth-child(even) { background: #f8fafd; }
  table.bc-items tbody td.right { text-align: right; }
  table.bc-items tbody td.center { text-align: center; }
  .bc-totaux { margin-top: 14px; display: flex; justify-content: flex-end; }
  .bc-totaux table { font-size: 11px; min-width: 320px; }
  .bc-totaux td { padding: 5px 10px; }
  .bc-totaux .lbl { color:#666; }
  .bc-totaux .val { text-align: right; font-weight: 600; }
  .bc-totaux .total-final td { background: #0E5C8A; color:white; font-size: 13px; font-weight: 800; padding: 8px 12px; }
  .bc-modalites { margin-top: 18px; border-left: 4px solid #F77F00; padding: 8px 14px; background: #fff7ed; font-size: 10.5px; }
  .bc-modalites ol { margin: 4px 0 4px 18px; padding: 0; }
  .bc-modalites li { margin: 2px 0; }
  .bc-conditions { display: flex; gap: 12px; margin-top: 12px; font-size: 11px; }
  .bc-conditions div { flex: 1; }
  .bc-conditions strong { color:#0E5C8A; }
  .bc-autorisation { margin-top: 24px; border-top: 2px solid #0E5C8A; padding-top: 14px; display: flex; justify-content: space-between; gap: 18px; }
  .bc-sig-box { flex: 1; }
  .bc-sig-box h4 { margin:0 0 6px; color:#0E5C8A; font-size: 11px; text-transform: uppercase; letter-spacing: 1px; }
  .bc-sig-area { border: 1px dashed #cbd5e1; min-height: 70px; padding: 6px; background: #fafbfc; border-radius: 4px; }
  .bc-sig-area img { max-height: 60px; }
  .bc-footer { margin-top: 22px; border-top: 1px solid #d0d7de; padding-top: 8px; text-align: center; font-size: 9px; color:#666; }
  .bc-footer .slog { color:#F77F00; font-weight: 700; font-style: italic; }
</style>

<div class="bc-page">
  <div class="bc-header">
    <div class="bc-logo">
      <img src="/assets/kya_hr/images/logo_kya.png" onerror="this.src='/files/vrai.png'">
    </div>
    <div class="bc-h-center">
      <h1>BON DE COMMANDE</h1>
      <p class="slogan">KYA, move beyond the sky!</p>
    </div>
    <div class="bc-h-right">
      <div class="bc-num">BC N°{{ doc.numero_bc }}</div>
      <div class="bc-date">{{ frappe.utils.formatdate(doc.date_bc, 'dd/MM/yyyy') }}</div>
      <div class="bc-prix">Lauréat "Start-up" BOAD 2018, 1<sup>er</sup> prix</div>
    </div>
  </div>

  <div class="bc-objet">
    <div class="lbl">Objet de la Commande</div>
    <div class="val">{{ doc.objet }}</div>
  </div>

  <div class="bc-section">
    <div class="bc-block">
      <h4>Fournisseur</h4>
      <p><strong>Nom:</strong> {{ doc.fournisseur_nom or '' }}</p>
      {% if doc.fournisseur_entreprise %}<p><strong>Entreprise:</strong> {{ doc.fournisseur_entreprise }}</p>{% endif %}
      {% if doc.fournisseur_adresse %}<p><strong>Adresse:</strong> {{ doc.fournisseur_adresse }}</p>{% endif %}
      <p><strong>Ville:</strong> {{ doc.fournisseur_ville or 'Lomé' }}</p>
      {% if doc.fournisseur_telephone %}<p><strong>Téléphone:</strong> {{ doc.fournisseur_telephone }}</p>{% endif %}
      {% if doc.fournisseur_email %}<p><strong>Email:</strong> {{ doc.fournisseur_email }}</p>{% endif %}
    </div>
    <div class="bc-block">
      <h4>Adresse de livraison</h4>
      <p><strong>Nom:</strong> KYA-Energy Group</p>
      <p><strong>Entreprise:</strong> KYA-Energy Group</p>
      <p><strong>Adresse:</strong> Agoè Logopé, non loin du CCL</p>
      <p><strong>Ville:</strong> Lomé</p>
      <p><strong>Téléphone:</strong> 70 45 34 81 / 99 90 32 44</p>
      <p><strong>Email:</strong> info@kya-energy.com</p>
    </div>
  </div>

  <table class="bc-items">
    <thead>
      <tr>
        <th style="width:50%">DESCRIPTION</th>
        <th class="center" style="width:12%">QUANTITÉ</th>
        <th class="right" style="width:18%">PRIX UNITAIRE (FCFA)</th>
        <th class="right" style="width:20%">TOTAL (FCFA)</th>
      </tr>
    </thead>
    <tbody>
      {% for it in doc.articles %}
      <tr>
        <td>{{ it.description }}</td>
        <td class="center">{{ '{:g}'.format(it.quantite or 0) }} {{ it.unite or '' }}</td>
        <td class="right">{{ fmt(it.prix_unitaire) }}</td>
        <td class="right">{{ fmt(it.total) }}</td>
      </tr>
      {% endfor %}
    </tbody>
  </table>

  <div class="bc-totaux">
    <table>
      <tr><td class="lbl">SOUS-TOTAL</td><td class="val">{{ fmt(doc.sous_total) }} XOF</td></tr>
      {% if doc.remise %}<tr><td class="lbl">REMISE</td><td class="val">- {{ fmt(doc.remise) }} XOF</td></tr>{% endif %}
      <tr><td class="lbl">TVA ({{ '{:g}'.format(doc.tva_taux or 0) }}%)</td><td class="val">{{ fmt(doc.tva_montant) }} XOF</td></tr>
      <tr class="total-final"><td>TOTAL (CFA)</td><td style="text-align:right">{{ fmt(doc.total_ttc) }}</td></tr>
    </table>
  </div>

  <div class="bc-conditions">
    <div><strong>Garantie:</strong> {{ doc.garantie or '12 mois' }}</div>
    <div><strong>Délai de livraison:</strong> {{ doc.delai_livraison or '72 heures' }}</div>
    <div><strong>Validité:</strong> {{ doc.validite or '30 jours' }}</div>
    <div><strong>Modalités:</strong> {{ doc.modalites_paiement or '100% à la livraison' }}</div>
  </div>

  <div class="bc-modalites">
    <strong>À l'attention du fournisseur :</strong>
    <ol>
      <li>Envoyer au moins une copie de votre facture.</li>
      <li>Faire un échantillon pour validation avant exécution du marché.</li>
      <li>Exécuter la commande conformément aux prix, modalités, mode de livraison et spécifications précisées dans notre dossier.</li>
      <li>Nous notifier 48h après réception du présent bon si vous ne pouvez livrer tel que précisé.</li>
      <li>Envoyer toutes les correspondances à : <strong>KYA-ENERGY GROUP</strong> — Agoè Logopé — akossiwa.ameogno@kya-energy.com — +228 70 45 34 81 / 99 90 32 44</li>
    </ol>
  </div>

  <div class="bc-autorisation">
    <div class="bc-sig-box">
      <h4>Autorisé par</h4>
      <div class="bc-sig-area">{% if doc.signature_dg %}<img src="{{ doc.signature_dg }}">{% endif %}</div>
      <p style="margin-top:6px; font-size:11px;"><strong>{{ doc.autorise_par_nom or '' }}</strong><br>{{ doc.autorise_par_fonction or 'Directrice Générale' }}</p>
    </div>
    <div class="bc-sig-box">
      <h4>Date</h4>
      <div class="bc-sig-area" style="display:flex;align-items:center;justify-content:center;font-size:14px;color:#0E5C8A;font-weight:700;">
        {{ frappe.utils.formatdate(doc.date_autorisation or doc.date_bc, 'dd/MM/yyyy') }}
      </div>
      {% if doc.cachet %}<p style="margin-top:6px; font-size:11px; color:#F77F00;"><strong>✓ Cachet apposé</strong></p>{% endif %}
    </div>
  </div>

  <div class="bc-footer">
    <p class="slog">KYA, move beyond the sky!</p>
    <p>08 BP 81101 Agoè-Logopé, Lomé-TOGO &nbsp;·&nbsp; www.kya-energy.com &nbsp;·&nbsp; info@kya-energy.com</p>
    <p>N° RCCM: TG-LOM 2015 B 975 &nbsp;·&nbsp; NIF: 1000430317 &nbsp;·&nbsp; CNSS: 48863</p>
  </div>
</div>
